var TOPICS_DATA = TOPICS_DATA || {};
TOPICS_DATA["cicd"] = TOPICS_DATA["cicd"] || {};
TOPICS_DATA["cicd"]["cicd-fundamentals"] = {"id":"cicd-fundamentals","title":"CI/CD Fundamentals","difficulty":"beginner","estimatedMinutes":20,"tldr":["CI/CD is a method of frequently delivering applications to customers by introducing automation into the stages of app development.","CI (Continuous Integration): developers merge changes to main branch frequently, each merge triggers automated build and test.","CD (Continuous Delivery/Deployment): code changes are automatically built, tested, and prepared for release to production."],"laymanDefinition":"CI/CD is like an automated factory assembly line for your software. When a developer submits code, the factory automatically tests it (CI), packages it, and gets it ready to ship (CD). In continuous deployment, it even ships it automatically. This catches bugs early and delivers features fast.","deepDive":[{"heading":"Continuous Integration","text":"Developers merge code to main branch multiple times daily. Each commit triggers automated build and test. Immediate feedback if build breaks or tests fail. Practice: feature flags, short-lived branches, trunk-based development."},{"heading":"Continuous Delivery vs Deployment","text":"Continuous Delivery: every change is ready for release to production, but deployment is manual on demand. Continuous Deployment: every change that passes tests is automatically deployed to production. Delivery gives human approval gate; Deployment is fully automated."},{"heading":"Benefits","text":"Faster time to market, reduced manual errors, consistent release process, frequent feedback loops, smaller changes easier to debug, increased developer productivity, faster recovery from failures."}],"interviewAnswer":"","interviewQuestions":[{"question":"What is Continuous Integration?","answer":"Frequently merging code changes to main branch with automated builds and tests on each merge."},{"question":"What is the difference between Continuous Delivery and Continuous Deployment?","answer":"Delivery: automated tests but manual deploy. Deployment: fully automated deploy after tests pass."},{"question":"What is trunk-based development?","answer":"Developers work on short-lived branches merged to main multiple times daily, avoiding long-lived feature branches."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">CI/CD Fundamentals</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Code Commit</text><text x=\"65\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Developer pushes</text><line x1=\"120\" y1=\"48\" x2=\"140\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"150\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"205\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CI Build</text><text x=\"205\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Auto test + build</text><line x1=\"260\" y1=\"48\" x2=\"280\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"290\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"345\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">CD Delivery</text><text x=\"345\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Auto deploy ready</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Production</text><text x=\"65\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Ship to users</text><text x=\"240\" y=\"130\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">CI/CD: Frequent integration (CI), automated delivery (CD). Faster releases, fewer errors.</text></svg>","codeExamples":[{"title":"Simple CI/CD Flow","useCase":"Pipeline stages.","code":"commit -> build -> test -> deploy\n# Each stage automated and triggered by previous success","description":""}],"mcqQuestions":[{"question":"What is the main benefit of CI?","options":["Slower releases","Faster feedback on integration issues","More documentation","Manual testing"],"answer":1,"explanation":"CI gives immediate feedback when code breaks the build or tests, catching issues early."}]};
TOPICS_DATA["cicd"]["cicd-pipeline"] = {"id":"cicd-pipeline","title":"CI/CD Pipeline","difficulty":"intermediate","estimatedMinutes":20,"tldr":["A CI/CD pipeline is an automated sequence of stages that code goes through from commit to deployment.","Typical stages: Source → Build → Test → Stage → Deploy. Each stage must succeed before the next starts.","Pipelines are defined as code (YAML/JSON) and version-controlled alongside the application."],"laymanDefinition":"A CI/CD pipeline is like an assembly line for your code. Each station does something: Source (get code), Build (compile/package), Test (run tests), Stage (deploy to test environment), Deploy (ship to production). The car moves to the next station only if the current station reports success.","deepDive":[{"heading":"Pipeline Stages","text":"Source: check out code from repository. Build: compile code, install dependencies, generate artifacts. Test: unit tests, integration tests, linting. Stage: deploy to staging/QA environment for further validation. Deploy: release to production (manual or automated). Post-deploy: smoke tests, monitoring alerts."},{"heading":"Pipeline as Code","text":"Pipeline definition stored in repository (version controlled). Benefits: reviewable, testable, reproducible, consistent across environments. Common formats: GitHub Actions YAML, GitLab CI YAML, Jenkinsfile (Groovy), CircleCI YAML."},{"heading":"Pipeline Best Practices","text":"Fail fast: run quickest tests first. Parallel stages where possible. Keep stages focused (one responsibility). Use cached dependencies. Version control pipeline config. Maintain pipeline as you maintain code."}],"interviewAnswer":"","interviewQuestions":[{"question":"What is a CI/CD pipeline?","answer":"An automated sequence of stages (source, build, test, deploy) that code passes through from commit to production."},{"question":"What does \"fail fast\" mean in pipelines?","answer":"Run quick checks (lint, unit tests) first to provide immediate feedback on common issues."},{"question":"Why define pipeline as code?","answer":"Version controlled, reviewable, reproducible, consistent across environments."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">CI/CD Pipeline</text><rect x=\"10\" y=\"35\" width=\"80\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"50\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Source</text><text x=\"50\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">git checkout</text><line x1=\"90\" y1=\"48\" x2=\"100\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"110\" y=\"35\" width=\"80\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"150\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Build</text><text x=\"150\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">npm install</text><line x1=\"190\" y1=\"48\" x2=\"200\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"210\" y=\"35\" width=\"80\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"250\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Test</text><text x=\"250\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">npm test</text><line x1=\"290\" y1=\"48\" x2=\"300\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"310\" y=\"35\" width=\"80\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"350\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Stage</text><text x=\"350\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Deploy QA</text><line x1=\"390\" y1=\"48\" x2=\"400\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"410\" y=\"35\" width=\"80\" height=\"25\" rx=\"4\" fill=\"#e83e8c\" stroke=\"#e83e8c\" stroke-width=\"1\"/><text x=\"450\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Deploy</text><text x=\"450\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Production</text><text x=\"240\" y=\"100\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">CI/CD Pipeline: Source → Build → Test → Stage → Deploy. Each stage gates the next.</text></svg>","codeExamples":[{"title":"Pipeline YAML","useCase":"GitHub Actions pipeline example.","code":"name: CI/CD Pipeline\non: [push]\njobs:\n  build:\n    runs-on: ubuntu-latest\n    steps:\n      - uses: actions/checkout@v4\n      - run: npm ci\n      - run: npm test","description":""}],"mcqQuestions":[{"question":"What is the fail-fast principle in pipelines?","options":["Run slowest tests first","Run quickest tests first for immediate feedback","Skip tests on failure","Deploy regardless"],"answer":1,"explanation":"Fail fast: run quick checks like linting and unit tests first so developers get immediate feedback."}]};
TOPICS_DATA["cicd"]["cicd-build-automation"] = {"id":"cicd-build-automation","title":"Build Automation","difficulty":"intermediate","estimatedMinutes":15,"tldr":["Build automation is the process of automating the creation of software builds and associated artifacts.","Includes: dependency resolution, compilation, asset bundling, code generation, packaging.","Tools: npm/pnpm/yarn (JS), Maven/Gradle (Java), pip (Python), make, Docker."],"laymanDefinition":"Build automation is like having a robot chef that follows a recipe to cook your software. It fetches ingredients (dependencies), mixes them (compiles), prepares the dish (bundles), and plates it (packages). The recipe is your build configuration — consistent every time.","deepDive":[{"heading":"Build Process","text":"Dependency installation: npm ci (clean install), pip install, mvn install. Compilation: TypeScript to JS, SASS to CSS, Babel transpilation. Bundling: Webpack, Vite, Rollup, Parcel. Code generation: GraphQL types, Prisma client, OpenAPI clients. Asset optimization: minification, image optimization, tree shaking."},{"heading":"Build Tools by Language","text":"JavaScript/TypeScript: npm, pnpm, yarn, webpack, vite, esbuild, rollup. Java: Maven, Gradle, Ant. Python: pip, poetry, setup.py. Go: go build, go mod. Rust: cargo build. C/C++: make, cmake, ninja. Docker: docker build."},{"heading":"Reproducible Builds","text":"Lock files: package-lock.json, yarn.lock, pnpm-lock.yaml. Version pinning: exact dependency versions. CI: use clean install (npm ci) for deterministic builds. Docker: multi-stage builds, pin base image versions."}],"interviewAnswer":"","interviewQuestions":[{"question":"What is build automation?","answer":"The automated process of compiling code, resolving dependencies, and packaging artifacts."},{"question":"What is the difference between npm install and npm ci?","answer":"npm ci: clean install from lockfile (faster, deterministic). npm install: may update lockfile."},{"question":"What is a lock file?","answer":"A file that records exact dependency versions (e.g., package-lock.json) ensuring reproducible builds."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Build Automation</text><rect x=\"10\" y=\"35\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"80\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Dependencies</text><text x=\"80\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">npm install / pip install</text><rect x=\"10\" y=\"65\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"80\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Compilation</text><text x=\"80\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">tsc, babel, sass</text><rect x=\"10\" y=\"95\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"80\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Bundling</text><text x=\"80\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">webpack, vite</text><rect x=\"10\" y=\"125\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"80\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Packaging</text><text x=\"80\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Docker, ZIP, JAR</text><text x=\"240\" y=\"170\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Build Automation: Automated compilation, bundling, and packaging. Reproducible via lock files.</text></svg>","codeExamples":[{"title":"Build Script","useCase":"Node.js build example.","code":"npm ci\nnpm run build\nnpm run test\ndocker build -t app:latest .","description":""}],"mcqQuestions":[{"question":"What ensures reproducible builds?","options":["Manual installation","Lock files and clean install","Latest versions","Global dependencies"],"answer":1,"explanation":"Lock files (like package-lock.json) and clean install commands ensure reproducible, deterministic builds."}]};
TOPICS_DATA["cicd"]["cicd-test-automation"] = {"id":"cicd-test-automation","title":"Test Automation in CI/CD","difficulty":"intermediate","estimatedMinutes":20,"tldr":["Test automation in CI/CD means running tests automatically on every code change, providing fast feedback on code quality.","Test types: unit tests (fast, isolated), integration tests (service interaction), end-to-end tests (full workflow), visual regression tests.","Test results gate the pipeline: failure in tests blocks the pipeline from proceeding to deployment."],"laymanDefinition":"Test automation is like having a quality control inspector that checks every product coming off the assembly line. If the inspector finds a defect, the product is sent back, preventing bad products from reaching customers. The earlier a defect is caught, the cheaper it is to fix.","deepDive":[{"heading":"Test Pyramid","text":"Unit tests (base, many): test individual functions/classes. Fast, no external dependencies. Integration tests (middle, some): test module/API interactions. May use test databases. E2E tests (top, few): test complete user flows. Slow, brittle. Strategy: >70% unit, ~20% integration, <10% E2E."},{"heading":"CI/CD Test Strategy","text":"Run unit tests on every commit (fast feedback). Run integration tests on PR to main. Run E2E tests on PR or scheduled (not on every commit). Run linting and type checking in parallel. Use test splitting/parallelism for large suites."},{"heading":"Test Reporting","text":"JUnit XML: standard test report format. Coverage reports: Istanbul (JS), JaCoCo (Java), coverage.py. Publish reports as pipeline artifacts. Failure notifications: Slack, email, GitHub commit status. Test flakiness detection and retry."}],"interviewAnswer":"","interviewQuestions":[{"question":"What is the test pyramid?","answer":"A model showing the ideal proportion: many unit tests (base), some integration tests (middle), few E2E tests (top)."},{"question":"What tests should run on every commit?","answer":"Unit tests (fast, focused). Integration and E2E tests run on PRs or schedules."},{"question":"What is test flakiness?","answer":"Tests that sometimes pass and sometimes fail without code changes. Should be quarantined and fixed."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Test Automation in CI/CD</text><rect x=\"10\" y=\"35\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"80\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Unit Tests</text><text x=\"80\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Fast, many, isolated</text><rect x=\"10\" y=\"65\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"80\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Integration</text><text x=\"80\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">API, DB interaction</text><rect x=\"10\" y=\"95\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"80\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">E2E Tests</text><text x=\"80\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Full workflows, few</text><text x=\"240\" y=\"140\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Test Automation: Unit tests on every commit, integration on PRs, E2E on PRs/schedules. Gate pipeline progression.</text></svg>","codeExamples":[{"title":"Test Commands","useCase":"Run tests in CI.","code":"npm run test:unit\nnpm run test:integration\nnpm run test:e2e","description":""}],"mcqQuestions":[{"question":"What is the recommended proportion of unit tests in the test pyramid?","options":["10%","50%","70%+","90%+"],"answer":2,"explanation":"The test pyramid recommends >70% unit tests (base), ~20% integration (middle), <10% E2E (top)."}]};
TOPICS_DATA["cicd"]["cicd-code-quality"] = {"id":"cicd-code-quality","title":"Linting & Code Quality","difficulty":"intermediate","estimatedMinutes":15,"tldr":["Linting analyzes source code for programmatic and stylistic errors, enforcing consistent coding standards.","Code quality tools go beyond linting to measure complexity, duplication, security, and maintainability.","Integrate linting early in the pipeline — fail fast on style issues before running expensive tests."],"laymanDefinition":"Linting is like a spell-checker and style-guide enforcer for code. It catches: missing semicolons, unused variables, incorrect indentation, potential bugs. Code quality tools are like a report card—they give your code a score for maintainability, security, and complexity.","deepDive":[{"heading":"Linting Tools","text":"JavaScript: ESLint (configurable rules), Prettier (formatting). TypeScript: typescript-eslint. Python: flake8, pylint, black. CSS: stylelint. Docker: hadolint. YAML: yamllint. Markdown: markdownlint. Pre-commit hooks: lint before commit."},{"heading":"Code Quality Tools","text":"Complexity: cyclomatic complexity, cognitive complexity. Duplication: copy-paste detection (CPD). Security: SonarQube, CodeQL, Snyk. Coverage: minimum coverage thresholds. Maintainability index: numerical score. Technical debt: estimated effort to fix issues."},{"heading":"CI/CD Integration","text":"Run linting first (fastest checks). Fail pipeline on lint errors. Enforce formatting (Prettier as gate). Publish quality reports as artifacts. Use quality gates to block merges below threshold."},{"heading":"SonarQube","text":"Popular code quality platform. Quality Gates: pass/fail based on metrics (coverage, bugs, vulnerabilities, code smells, duplication). Supports 30+ languages. PR decoration: annotations in PR diff. CI integration: sonar-scanner command."}],"interviewAnswer":"","interviewQuestions":[{"question":"What is linting?","answer":"Automated analysis of source code to detect programming errors, bugs, and stylistic inconsistencies."},{"question":"What is Prettier?","answer":"An opinionated code formatter that enforces consistent style automatically."},{"question":"What is a SonarQube Quality Gate?","answer":"A set of threshold conditions (coverage, bugs, etc.) that code must meet to pass quality checks."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Linting & Code Quality</text><rect x=\"10\" y=\"35\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"80\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">ESLint</text><text x=\"80\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Code analysis</text><rect x=\"10\" y=\"65\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"80\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Prettier</text><text x=\"80\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Formatting</text><rect x=\"10\" y=\"95\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"80\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">SonarQube</text><text x=\"80\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Quality metrics</text><rect x=\"10\" y=\"125\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"80\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Quality Gate</text><text x=\"80\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Pass/fail threshold</text><text x=\"240\" y=\"170\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Linting & Code Quality: ESLint, Prettier, SonarQube. Automated code analysis gates the pipeline.</text></svg>","codeExamples":[{"title":"Lint in CI","useCase":"Run linting and formatting checks.","code":"npm run lint\nnpx prettier --check .\nnpx sonar-scanner","description":""}],"mcqQuestions":[{"question":"Where should linting run in the pipeline?","options":["At the end","In the first stage (fail fast)","After deployment","Never in CI"],"answer":1,"explanation":"Linting should run early (first stage) as it provides fast feedback on common issues."}]};
TOPICS_DATA["cicd"]["cicd-artifacts"] = {"id":"cicd-artifacts","title":"Artifacts & Build Outputs","difficulty":"intermediate","estimatedMinutes":15,"tldr":["Artifacts are the outputs of the build process: compiled code, packages, Docker images, reports, and binaries.","Artifacts are stored, versioned, and passed between pipeline stages or consumed by downstream systems.","Common registries: Docker Hub, GitHub Packages, npm registry, JFrog Artifactory, S3."],"laymanDefinition":"Artifacts are like the finished products coming off the assembly line. They need to be stored in a warehouse (artifact registry) with labels and version numbers. Downstream stages (deployment) or other teams can fetch specific versions from the warehouse as needed.","deepDive":[{"heading":"Artifact Types","text":"Containers: Docker images pushed to registry (Docker Hub, ECR, GCR). Language packages: npm packages, JARs, Python wheels, NuGet packages. Binaries: compiled executables, installers. Reports: test reports, coverage reports, lint reports. Deployment packages: ZIP/TAR archives."},{"heading":"Artifact Storage","text":"Pipeline built-in: GitHub Actions artifacts, GitLab artifacts, Jenkins artifacts. Registry: Docker Registry (Harbor, Docker Hub), Package Registry (npm, PyPI). Cloud storage: S3, GCS, Azure Blob. Version policy: keep recent N versions, delete old ones."},{"heading":"Best Practices","text":"Version every artifact uniquely (commit SHA or semver). Immutable artifacts: never overwrite a published version. Clean up old artifacts. Use artifact promotion (dev → staging → prod). Sign artifacts for security. Scan artifacts for vulnerabilities."}],"interviewAnswer":"","interviewQuestions":[{"question":"What are pipeline artifacts?","answer":"Build outputs (binaries, containers, reports) stored and passed between pipeline stages."},{"question":"What is an artifact registry?","answer":"A storage service for versioned artifacts (Docker Hub, npm registry, GitHub Packages)."},{"question":"What is artifact promotion?","answer":"Promoting an artifact through environments: dev → staging → production after validation."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Artifacts & Build Outputs</text><rect x=\"10\" y=\"35\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"80\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Build Code</text><text x=\"80\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Compile & package</text><line x1=\"150\" y1=\"48\" x2=\"170\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"180\" y=\"35\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"250\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Artifact Registry</text><text x=\"250\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Store versioned</text><line x1=\"320\" y1=\"48\" x2=\"340\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"350\" y=\"35\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"420\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Deploy</text><text x=\"420\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Consume artifacts</text><text x=\"240\" y=\"100\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Artifact Management: Store versioned build outputs. Pass between stages. Registries: Docker Hub, npm, S3.</text></svg>","codeExamples":[{"title":"Docker Artifact","useCase":"Build and push image.","code":"docker build -t app:${GITHUB_SHA} .\ndocker push ghcr.io/user/app:${GITHUB_SHA}","description":""}],"mcqQuestions":[{"question":"Should artifacts be overwritten?","options":["Yes, keep latest only","No, artifacts should be immutable","Only for dev builds","Always"],"answer":1,"explanation":"Artifacts should be immutable — never overwrite a published version. Use unique version identifiers."}]};
TOPICS_DATA["cicd"]["cicd-docker"] = {"id":"cicd-docker","title":"Docker in CI/CD","difficulty":"intermediate","estimatedMinutes":20,"tldr":["Docker provides consistent, reproducible environments for building, testing, and deploying applications in CI/CD pipelines.","Containers ensure the same dependencies, OS, and configuration across development, testing, and production.","Key concepts: Dockerfile, docker build, docker push/pull, multi-stage builds, Docker Compose for testing."],"laymanDefinition":"Docker in CI/CD is like having a standardized shipping container for your software. Every container is built the same way, carries the same contents, and works identically on any system. This eliminates \"it works on my machine\" problems across the pipeline.","deepDive":[{"heading":"Docker Build in CI","text":"Dockerfile defines the environment. docker build creates the image. Use .dockerignore to exclude unnecessary files. Tag images with commit SHA and/or branch. Multi-stage builds: separate build and runtime dependencies (smaller images). BuildKit: faster, parallel layer builds."},{"heading":"Docker for Testing","text":"Docker Compose: spin up test dependencies (DB, Redis, queues). Ephemeral environments: create per-test containers, destroy after. Service containers: GitHub Actions supports services. Database migrations in containers. Parallel test execution using container isolation."},{"heading":"Docker Deploy","text":"Push image to registry after successful tests. Deploy by pulling and running new image (rolling update). Blue-green: switch traffic between old and new container group. Kubernetes: update Deployment image tag."},{"heading":"Best Practices","text":"Pin base image versions (not \"latest\"). Use distroless or Alpine base. Scan images for vulnerabilities. Small images = faster pulls. Cache layers effectively. Use docker build --cache-from for CI caching."}],"interviewAnswer":"","interviewQuestions":[{"question":"Why use Docker in CI/CD?","answer":"Consistent environments across build, test, and production. Eliminates environment-specific issues."},{"question":"What is a multi-stage build?","answer":"A Dockerfile with multiple FROM statements: build stage (large) and runtime stage (small, only runtime deps)."},{"question":"What is Docker BuildKit?","answer":"An improved builder with parallel layer processing, better caching, and faster builds."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Docker in CI/CD</text><rect x=\"10\" y=\"35\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"80\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Dockerfile</text><text x=\"80\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Define environment</text><line x1=\"150\" y1=\"48\" x2=\"170\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"180\" y=\"35\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"250\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">docker build</text><text x=\"250\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Create image</text><line x1=\"320\" y1=\"48\" x2=\"340\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"350\" y=\"35\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"420\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">docker push</text><text x=\"420\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Upload to registry</text><rect x=\"10\" y=\"65\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"80\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">docker pull</text><text x=\"80\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Download & deploy</text><text x=\"240\" y=\"130\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Docker in CI/CD: Consistent environments, multi-stage builds, container testing, image registries.</text></svg>","codeExamples":[{"title":"Docker CI Commands","useCase":"Build, test, and push.","code":"docker build -t app:${SHA} .\ndocker compose up -d db\ndocker compose run tests\ndocker push ghcr.io/user/app","description":""},{"title":"Multi-stage Dockerfile","useCase":"Distroless runtime image.","code":"FROM node:20 AS build\nWORKDIR /app\nCOPY . .\nRUN npm ci && npm run build\nFROM gcr.io/distroless/nodejs20-debian12\nCOPY --from=build /app/dist ./dist\nCMD [\"dist/index.js\"]","description":""}],"mcqQuestions":[{"question":"What is the benefit of multi-stage builds?","options":["Faster internet","Smaller final images","More layers","Easier debugging"],"answer":1,"explanation":"Multi-stage builds separate build dependencies (large) from runtime (small), resulting in much smaller final images."}]};
TOPICS_DATA["cicd"]["cicd-environments"] = {"id":"cicd-environments","title":"Environment Management","difficulty":"intermediate","estimatedMinutes":15,"tldr":["Environment management involves setting up and maintaining separate stages (dev, staging, production) for the software delivery lifecycle.","Each environment should mirror production as closely as possible to catch issues early.","Tools: Docker Compose, Terraform, Kubernetes, CloudFormation, environment variables."],"laymanDefinition":"Environment management is like having different rooms in a house: the workshop (development), showroom (staging), and retail store (production). You build and test in the workshop, verify in the showroom, and only perfect products reach the retail store.","deepDive":[{"heading":"Environment Types","text":"Development: dev machine, local containers, dev server. Unlimited changes, unpolished. Staging: pre-production, mirrors prod, QA testing, integration tests. Production: live user traffic, high availability, monitoring, strict access. Optional: QA, UAT, canary, preview environments."},{"heading":"Environment Parity","text":"Keep environments as similar as possible. Same OS, same dependencies, same config files. Use Docker containers for consistency. Infrastructure as Code for reproducible environments. Version-controlled config. Don\\'t hardcode environment-specific values."},{"heading":"Configuration Management","text":"Environment variables for config differences (DB URL, API keys). Config files per environment. Secret management: never in code. Feature flags for per-environment behaviors. Environment-specific CI/CD jobs/stages."}],"interviewAnswer":"","interviewQuestions":[{"question":"What are the three main environments?","answer":"Development (coding), Staging (testing), Production (live)."},{"question":"What is environment parity?","answer":"Keeping environments as similar as possible to catch production issues in earlier stages."},{"question":"How should configuration differ between environments?","answer":"Via environment variables (not hardcoded values). Secrets stored in secret managers."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Environment Management</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Development</text><text x=\"60\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Coding & unit tests</text><line x1=\"110\" y1=\"48\" x2=\"130\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"140\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"190\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Staging</text><text x=\"190\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">QA & integration</text><line x1=\"240\" y1=\"48\" x2=\"260\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"270\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"320\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Production</text><text x=\"320\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Live users</text><text x=\"240\" y=\"110\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Environment Management: Dev → Staging → Production. Parity is crucial. Configure via env vars, not hardcoding.</text></svg>","codeExamples":[{"title":"Env Config","useCase":"Using environment variables.","code":"export DATABASE_URL=\"postgres://...\"\nexport API_KEY=${{ secrets.API_KEY }}","description":""}],"mcqQuestions":[{"question":"What is the most important principle in environment management?","options":["Use latest software","Environment parity (keep environments similar)","Manual configuration","Separate codebases"],"answer":1,"explanation":"Environment parity — keeping dev, staging, and prod as similar as possible — prevents environment-specific bugs."}]};
TOPICS_DATA["cicd"]["cicd-secrets"] = {"id":"cicd-secrets","title":"Secrets Management in CI/CD","difficulty":"intermediate","estimatedMinutes":20,"tldr":["Secrets management involves securely storing and using sensitive data (API keys, passwords, tokens) in CI/CD pipelines.","Secrets should never be hardcoded in code, committed to repos, or exposed in pipeline logs.","Solutions: built-in CI/CD secrets, HashiCorp Vault, AWS Secrets Manager, Azure Key Vault, Doppler."],"laymanDefinition":"Secrets management is like a secure vault for your passwords. Instead of writing the vault combination on a sticky note (hardcoding in code), you store it in a secure vault and only authorized processes can retrieve it at runtime. The pipeline can use it without knowing what it is.","deepDive":[{"heading":"Built-in Secrets","text":"GitHub Actions: Settings → Secrets → Actions. Referenced as ${{ secrets.MY_SECRET }}. Encrypted at rest, masked in logs. Organization secrets for shared use. Environment secrets for environment-specific."},{"heading":"External Secret Managers","text":"HashiCorp Vault: dynamic secrets, leasing, revocation. AWS Secrets Manager: automatic rotation, IAM integration. Azure Key Vault: Azure AD authentication. Doppler: multi-cloud secret management. External secrets operator for Kubernetes."},{"heading":"Best Practices","text":"Never commit secrets to Git. Use .env in .gitignore for local dev. In CI: use built-in secrets or integrate Vault. Rotate secrets regularly. Least privilege: grant minimum access. Audit secret access. Mask secrets in logs. Scan for committed secrets (git secrets, truffleHog)."},{"heading":"Secret Scanning","text":"Pre-commit hooks: detect secrets before commit (git-secrets, detect-secrets). CI scanning: truffleHog, Gitleaks in pipeline. GitHub secret scanning: automatic detection. Remediation: rotate leaked secrets immediately."}],"interviewAnswer":"","interviewQuestions":[{"question":"How are secrets stored in GitHub Actions?","answer":"In Settings → Secrets → Actions. Referenced as ${{ secrets.NAME }}."},{"question":"What is HashiCorp Vault?","answer":"A secret management tool for storing, accessing, and rotating secrets with dynamic secrets and leasing."},{"question":"What should you do if a secret is leaked?","answer":"Immediately rotate/revoke the secret and scan for unauthorized access."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Secrets Management in CI/CD</text><rect x=\"10\" y=\"35\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"80\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Code</text><text x=\"80\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">NO hardcoded secrets</text><line x1=\"150\" y1=\"48\" x2=\"170\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"180\" y=\"35\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"250\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Secret Manager</text><text x=\"250\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Encrypted storage</text><line x1=\"320\" y1=\"48\" x2=\"340\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"350\" y=\"35\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"420\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Pipeline</text><text x=\"420\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">${{ secrets.KEY }}</text><text x=\"240\" y=\"110\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Secrets: Never in code. Use CI/CD built-in secrets or external managers (Vault, AWS Secrets Manager).</text></svg>","codeExamples":[{"title":"GitHub Actions Secrets","useCase":"Use secrets in workflows.","code":"steps:\n  - run: echo ${{ secrets.DEPLOY_KEY }} | docker login --username --password-stdin","description":""}],"mcqQuestions":[{"question":"How are GitHub Actions secrets masked?","options":["They are visible in logs","They are automatically masked in log output","They cannot be used","They expire after 1 hour"],"answer":1,"explanation":"GitHub Actions automatically masks secrets in log output, replacing them with ***."}]};
TOPICS_DATA["cicd"]["cicd-triggers"] = {"id":"cicd-triggers","title":"Pipeline Triggers","difficulty":"beginner","estimatedMinutes":10,"tldr":["Pipeline triggers define when a CI/CD pipeline should run — events that kick off the automated workflow.","Common triggers: push to branch, pull request, schedule (cron), manual dispatch, tag creation, upstream pipeline completion.","Triggers can be filtered by branch, path, file changes, and activity type."],"laymanDefinition":"Pipeline triggers are like alarm clocks for your automation. You can set them to go off: every time someone pushes code, when a PR is opened, at 3 AM daily, or when someone manually presses a button. You can also say \"only trigger if changes are in the src folder on the main branch.\"","deepDive":[{"heading":"Code Triggers","text":"Push: trigger on every commit to specified branches. Pull request: trigger on PR open, sync, or reopen. Tag: trigger when tags matching a pattern are pushed. Filtering: branches, paths (include/exclude), file types, activity types."},{"heading":"Time Triggers","text":"Schedule: cron syntax (e.g., nightly builds: \"0 2 * * *\"). Periodic: run every X hours/days. Manual (workflow_dispatch): button in GitHub UI. Can include input parameters for flexibility."},{"heading":"Event Triggers","text":"Upstream pipeline completion (workflow_run): chain pipelines. Issue events: dependency updates, label changes. Release events: trigger on new release. Webhooks: external system triggers via API. Repository dispatch: custom events from GitHub API."},{"heading":"Filtering Best Practices","text":"Run tests on all branches but deploy only from main. Run full suite on main PRs, quick checks on other branches. Path filters: skip docs-only changes if they don\\'t affect code."}],"interviewAnswer":"","interviewQuestions":[{"question":"What are common pipeline triggers?","answer":"Push, Pull Request, Schedule (cron), Manual Dispatch, Tag creation."},{"question":"How to skip pipeline for docs-only changes?","answer":"Use path filters: paths: [src/**, tests/**] — only trigger when these paths change."},{"question":"What does workflow_dispatch enable?","answer":"Manual pipeline triggering from GitHub UI with optional input parameters."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Pipeline Triggers</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Push</text><text x=\"60\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Code commit</text><rect x=\"10\" y=\"65\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"60\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Pull Request</text><text x=\"60\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Open/update</text><rect x=\"10\" y=\"95\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"60\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Schedule</text><text x=\"60\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Cron timer</text><rect x=\"10\" y=\"125\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"60\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Manual</text><text x=\"60\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">workflow_dispatch</text><text x=\"240\" y=\"170\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Pipeline Triggers: Push, PR, schedule, manual, tags, upstream. Filter by branch, path, activity type.</text></svg>","codeExamples":[{"title":"Trigger Filters","useCase":"Branch and path filters.","code":"on:\n  push:\n    branches: [main]\n    paths: [src/**, tests/**]","description":""}],"mcqQuestions":[{"question":"What cron trigger runs a pipeline daily at 2 AM?","options":["*/2 * * *","0 2 * * *","2 0 * * *","0 0 2 * *"],"answer":1,"explanation":"\"0 2 * * *\" means minute 0, hour 2 (2 AM), every day, every month, every day of week."}]};
TOPICS_DATA["cicd"]["cicd-parallel"] = {"id":"cicd-parallel","title":"Parallel Execution","difficulty":"intermediate","estimatedMinutes":15,"tldr":["Parallel execution runs independent pipeline jobs simultaneously to reduce total pipeline duration.","Strategies: matrix (multi-version), fan-out (split tests), parallel stages (independent tasks).","Parallelism trades compute resources for speed — runs faster but uses more concurrent runners."],"laymanDefinition":"Parallel execution is like having multiple checkout lines at a supermarket. Instead of one line moving slowly (sequential), multiple lines run at the same time (parallel). Each line handles different items, and everything finishes faster.","deepDive":[{"heading":"Matrix Strategy","text":"Test across OS × version combinations. Example: ubuntu × Node 16,18,20 + windows × Node 16,18,20 = 6 parallel jobs. Useful for compatibility testing. Exclude known incompatibilities. Include additional configurations."},{"heading":"Parallel Stages","text":"Independent stages run concurrently: lint + unit tests + security scan all at once. Dependent stages must wait: build → (lint + unit_test + security) parallel → deploy. Use dependency graphs to express relationships."},{"heading":"Test Splitting","text":"Split large test suites across multiple jobs. By file: test_1.py runs in job A, test_2.py in job B. By timing: balance splits by historical test duration. Tools: jest --shard, pytest-xdist (distributed), playwright --shard."}],"interviewAnswer":"","interviewQuestions":[{"question":"What is a matrix build?","answer":"Running identical jobs across different OS/version combinations simultaneously."},{"question":"What is test splitting?","answer":"Dividing a large test suite across multiple parallel jobs for faster execution."},{"question":"What is a dependency graph in pipelines?","answer":"A DAG that defines which jobs depend on which, enabling parallel execution of independent jobs."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Parallel Execution</text><rect x=\"10\" y=\"35\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"80\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Job A: Lint</text><text x=\"80\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Runs in parallel</text><rect x=\"10\" y=\"65\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"80\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Job B: Unit Tests</text><text x=\"80\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Runs in parallel</text><rect x=\"10\" y=\"95\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"80\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Job C: Security</text><text x=\"80\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Runs in parallel</text><rect x=\"10\" y=\"125\" width=\"200\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"110\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Dependent: Deploy</text><text x=\"110\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Waits for A+B+C</text><text x=\"240\" y=\"170\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Parallel Execution: Matrix builds, test splitting, parallel stages. Faster pipelines, more resource usage.</text></svg>","codeExamples":[{"title":"Matrix Jobs","useCase":"GitHub Actions matrix strategy.","code":"strategy:\n  matrix:\n    os: [ubuntu-latest, windows-latest]\n    node: [16, 18, 20]\nruns-on: ${{ matrix.os }}","description":""}],"mcqQuestions":[{"question":"What is the tradeoff of parallel execution?","options":["Slower feedback","More resources for faster execution","Less test coverage","Simpler debugging"],"answer":1,"explanation":"Parallel execution uses more concurrent resources (runners) but reduces total pipeline execution time."}]};
TOPICS_DATA["cicd"]["cicd-caching"] = {"id":"cicd-caching","title":"Pipeline Caching","difficulty":"intermediate","estimatedMinutes":15,"tldr":["Pipeline caching stores frequently accessed data between pipeline runs to speed up execution.","What to cache: package manager dependencies (node_modules, ~/.m2, vendor/bundle), Docker layers, build outputs.","Cache key strategy: use lockfile hash for dependency cache, OS + version for toolchain cache."],"laymanDefinition":"Pipeline caching is like keeping your frequently used tools on your workbench instead of putting them away in the closet after every project. If you caches npm packages between builds, each build doesn't have to re-download them — just check if the package.json changed.","deepDive":[{"heading":"Cache Types","text":"Dependency cache: npm cache, pip cache, Maven local repo, Bundler, Go module cache. Docker cache: Docker layers, BuildKit cache. Build cache: compiled outputs, webpack cache, Gradle cache. Tools cache: SDKs (Go, .NET, Java), Python versions."},{"heading":"Cache Key Strategy","text":"Primary key: hash of lockfile (e.g., package-lock.json). Restore keys: fallback to partial match (e.g., os-node- prefix). Invalidation: change key when dependencies change. Cache hit: restores dependencies (no download). Cache miss: downloads fresh, saves for next run."},{"heading":"Best Practices","text":"Cache immutable dependencies only (lockfile-based). Set appropriate cache size limits. Clean cache periodically. Use CI-native caching when available. Keep cache keys precise enough to avoid stale caches. Separate caches per OS (different binaries)."}],"interviewAnswer":"","interviewQuestions":[{"question":"What is pipeline caching?","answer":"Storing dependencies and build outputs between pipeline runs to avoid re-downloading/re-building."},{"question":"What makes a good cache key?","answer":"A hash of the lockfile (e.g., hashFiles(\\'**/package-lock.json\\')). Changes when dependencies change, invalidating cache."},{"question":"What should NOT be cached?","answer":"Mutable outputs, environment-specific files, large rarely-used data."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Pipeline Caching</text><rect x=\"10\" y=\"35\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"80\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">First Run</text><text x=\"80\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Cache miss, download</text><line x1=\"150\" y1=\"48\" x2=\"170\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"180\" y=\"35\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"250\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Cache Saved</text><text x=\"250\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Store dependencies</text><line x1=\"320\" y1=\"48\" x2=\"340\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"350\" y=\"35\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"420\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Next Run</text><text x=\"420\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Cache hit, restore</text><text x=\"240\" y=\"110\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Pipeline Caching: Store deps between runs. Use lockfile hash as cache key. Faster pipelines, less network use.</text></svg>","codeExamples":[{"title":"Cache in Actions","useCase":"Cache npm dependencies.","code":"- uses: actions/cache@v4\n  with:\n    path: ~/.npm\n    key: ${{ runner.os }}-node-${{ hashFiles('**/package-lock.json') }}","description":""}],"mcqQuestions":[{"question":"What causes a cache miss?","options":["Running pipeline twice","Lockfile changed (different hash)","Time of day","Number of jobs"],"answer":1,"explanation":"Cache misses when the cache key doesn\\'t match — typically when the lockfile hash changes (dependencies added/updated)."}]};
TOPICS_DATA["cicd"]["cicd-blue-green"] = {"id":"cicd-blue-green","title":"Blue-Green Deployment","difficulty":"intermediate","estimatedMinutes":20,"tldr":["Blue-green deployment runs two identical production environments (blue and green), switching traffic between them for zero-downtime releases.","One environment serves live traffic while the other is updated. After validation, traffic switches to the updated environment.","If issues arise, traffic instantly switches back to the previous environment (instant rollback)."],"laymanDefinition":"Blue-green deployment is like having two identical restaurants side by side. One (blue) is serving customers while you renovate the other (green). When green is ready, you move all customers to green. If diners don't like something, you instantly move them back to blue.","deepDive":[{"heading":"How It Works","text":"Two identical environments, each independently deployable. Currently live (Blue) serves all traffic. Deploy new version to idle (Green). Run smoke tests on Green. Switch router/load balancer from Blue to Green. Blue becomes idle, ready for next deployment."},{"heading":"Benefits","text":"Zero-downtime deployments: no traffic interruption. Instant rollback: switch back if issues found. No version mixing: all instances serve same version. Full environment validation before traffic hits. Simple routing logic: active/inactive toggle."},{"heading":"Implementation","text":"DNS: change DNS record to target new env (slow propagation). Load balancer: switch target group (AWS ALB, Nginx upstream). Kubernetes: switch Service selector labels. Service mesh: traffic routing rules (Istio, Linkerd). Database: both envs share DB or use backward-compatible schema."},{"heading":"Considerations","text":"Database schema changes must be backward compatible. Cost: 2x infrastructure during deployment. State: handle sessions, caches, file systems. Test the rollback: verify switching back works. Automation: CI/CD pipeline automates the switch."}],"interviewAnswer":"","interviewQuestions":[{"question":"What is blue-green deployment?","answer":"Two identical environments with traffic switched between them for zero-downtime deployments."},{"question":"What is the main benefit?","answer":"Instant rollback: switch traffic back to the previous environment if issues occur."},{"question":"What is a key consideration for databases?","answer":"Schema changes must be backward compatible since both environments access the same database."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Blue-Green Deployment</text><rect x=\"10\" y=\"35\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"80\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Blue (Live)</text><text x=\"80\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Current traffic</text><rect x=\"10\" y=\"65\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"80\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Green (Idle)</text><text x=\"80\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Deploy new version</text><line x1=\"150\" y1=\"48\" x2=\"170\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"180\" y=\"65\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"250\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Switch Traffic</text><text x=\"250\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Load balancer</text><rect x=\"10\" y=\"95\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"80\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Green (Live)</text><text x=\"80\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">New version active</text><text x=\"240\" y=\"140\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Blue-Green: Two identical environments. Switch traffic between them. Instant rollback, zero-downtime.</text></svg>","codeExamples":[{"title":"K8s Blue-Green","useCase":"Switch service selector.","code":"kubectl patch service myapp -p '{\"spec\":{\"selector\":{\"version\":\"green\"}}}'\n# Instantly switches traffic to green","description":""}],"mcqQuestions":[{"question":"What is the key database challenge with blue-green?","options":["Cost","Schema backward compatibility","Performance","Backup"],"answer":1,"explanation":"Both blue and green environments share the database, so schema changes must be backward compatible to support both versions."}]};
TOPICS_DATA["cicd"]["cicd-canary"] = {"id":"cicd-canary","title":"Canary Deployment","difficulty":"intermediate","estimatedMinutes":20,"tldr":["Canary deployment gradually routes a small percentage of traffic to a new version before full rollout.","Start with 1-5% traffic to canary, monitor metrics (errors, latency, etc.), gradually increase if healthy.","If issues detected, canary is automatically rolled back (traffic redirected to stable version)."],"laymanDefinition":"Canary deployment is like testing a new recipe on a few customers before serving it to the whole restaurant. If the first customers like it (no errors, good performance), you serve it to more people, then everyone. If they complain, you stop serving it immediately.","deepDive":[{"heading":"Canary Strategy","text":"Initial: deploy new version to canary (1-5% of instances/traffic). Monitor: track error rates, latency, CPU, business metrics (conversion, signups). Gradual increase: 10%, 25%, 50%, 100% if health checks pass. Rollback: instant if metrics degrade. Full rollout: all traffic on new version."},{"heading":"Implementation","text":"Load balancer weighted routing: Nginx, AWS ALB, GCP HTTP LB. Service mesh: Istio VirtualService with weighted destinations. Kubernetes: multiple Deployments, split Service via selector or mesh. Feature flags: enable for specific user segments. Progressive delivery: Flagger, Argo Rollouts."},{"heading":"Metrics for Canary","text":"Error rate (5xx, exceptions). Latency (p50, p95, p99). Resource usage (CPU, memory). Business metrics (conversion rate, signups). Log analysis (error logs, warnings). Infrastructure metrics (connections, throughput). Auto-rollback on threshold breach."},{"heading":"Canary vs Blue-Green","text":"Blue-Green: binary switch (100% on one). Canary: gradual transition. Blue-Green: simpler, instant rollback. Canary: safer (catch issues at low traffic), slower rollout. Choose: blue-green for confident changes, canary for risky changes."}],"interviewAnswer":"","interviewQuestions":[{"question":"What is canary deployment?","answer":"Gradually routing increasing traffic to a new version while monitoring metrics."},{"question":"What percentage traffic typically starts a canary?","answer":"1-5% of traffic routed to the new version initially."},{"question":"What is progressive delivery?","answer":"Automated canary management with metrics-based rollout and rollback (Flagger, Argo Rollouts)."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Canary Deployment</text><rect x=\"10\" y=\"35\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"80\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Canary 5%</text><text x=\"80\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">New version, few users</text><line x1=\"150\" y1=\"48\" x2=\"170\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"180\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"230\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Monitor</text><text x=\"230\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Track metrics</text><rect x=\"10\" y=\"65\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"80\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">50%</text><text x=\"80\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Expand if healthy</text><rect x=\"10\" y=\"95\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"80\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">100%</text><text x=\"80\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Full rollout</text><text x=\"240\" y=\"140\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Canary: Gradually increase traffic to new version. Monitor metrics. Auto-rollback on issues. Safer than blue-green for risky changes.</text></svg>","codeExamples":[{"title":"Istio Canary","useCase":"Weighted traffic routing.","code":"apiVersion: networking.istio.io/v1beta1\nkind: VirtualService\nspec:\n  http:\n  - route:\n    - destination:\n        host: myapp\n        subset: stable\n      weight: 95\n    - destination:\n        host: myapp\n        subset: canary\n      weight: 5","description":""}],"mcqQuestions":[{"question":"What happens if canary metrics degrade?","options":["Full rollout continues","Automatic rollback to stable","Pipeline blocks","Nothing"],"answer":1,"explanation":"If canary metrics degrade (error rate, latency), the deployment automatically rolls back to the stable version."}]};
TOPICS_DATA["cicd"]["cicd-rollback"] = {"id":"cicd-rollback","title":"Rollback Strategies","difficulty":"intermediate","estimatedMinutes":15,"tldr":["Rollback is the process of reverting a deployment to a previous known-good version when issues are detected.","Strategies: instant (blue-green), gradual (canary rollback), git revert + redeploy, database rollback.","Key: rollbacks should be automated, tested, and fast (ideally sub-minute)."],"laymanDefinition":"Rollback is like an \"undo\" button for deployments. If a new version causes errors, you immediately switch back to the last working version. A good rollback strategy is essential — not \"if\" something will go wrong, but \"when.\"","deepDive":[{"heading":"Rollback Methods","text":"Blue-green switch: flip traffic back to previous environment (instant). Container rollback: kubectl rollout undo deployment/myapp. Git revert: revert commit + redeploy. Database: schema rollback scripts or backup restore. Feature flag: turn off problematic feature (no deploy needed)."},{"heading":"Automated Rollback","text":"Health check failures auto-trigger rollback. Metrics degradation (error rate > 1%). Timeout: if new version unhealthy after X minutes. Pipeline: automated revert + deploy. Break glass: manual emergency button. Rollback history: keep last N versions."},{"heading":"Database Rollback","text":"Backward-compatible migrations: add before remove. Versioned migrations: each DB change is reversible. Flyway, Liquibase: support undo (but dangerous). Blue-green with shared DB: both versions must work. Golden rule: never roll back a database schema change automatically — write a forward fix instead."},{"heading":"Pitfalls","text":"Schema changes make rollback hard. Data migrations can\\'t be reverted (data loss). Cached data may reference new schema. External APIs may not support rollback. Rollback should be a regular deployment of previous version (not a special process)."}],"interviewAnswer":"","interviewQuestions":[{"question":"What is the fastest rollback method?","answer":"Blue-green switch: instant traffic flip to previous environment."},{"question":"What is the golden rule of database rollbacks?","answer":"Don\\'t automate schema rollbacks — write forward fixes instead. Backward-compatible changes only."},{"question":"What is kubectl rollout undo?","answer":"Kubernetes command to revert a Deployment to the previous revision."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Rollback Strategies</text><rect x=\"10\" y=\"35\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"80\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Deploy V2</text><text x=\"80\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">New version goes live</text><rect x=\"10\" y=\"65\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"80\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Issue Detected</text><text x=\"80\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Errors, latency spike</text><line x1=\"150\" y1=\"48\" x2=\"170\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"180\" y=\"35\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"250\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Rollback V1</text><text x=\"250\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Revert to previous</text><text x=\"240\" y=\"110\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Rollback: Revert to previous version on failure. Blue-green = instant. DB rollbacks need special care.</text></svg>","codeExamples":[{"title":"K8s Rollback","useCase":"Kubernetes rollout undo.","code":"kubectl rollout undo deployment/myapp\nkubectl rollout status deployment/myapp","description":""}],"mcqQuestions":[{"question":"What is the recommended approach for database rollbacks?","options":["Automated schema rollback","Write forward fix instead of reverting schema","Restore from backup","Ignore the issue"],"answer":1,"explanation":"Instead of rolling back schema changes (which can cause data loss), write forward-fix migrations to correct issues."}]};
TOPICS_DATA["cicd"]["cicd-deploy-envs"] = {"id":"cicd-deploy-envs","title":"Deployment Environments & Promotion","difficulty":"intermediate","estimatedMinutes":15,"tldr":["Deployment promotion moves artifacts through environments: dev → staging → production, with validation gates between each step.","Promotion gates: automated tests, manual approval, security scan, performance benchmark, compliance check.","Each environment should be progressively more production-like, with stricter gates."],"laymanDefinition":"Deployment promotion is like a career ladder for your code. It starts as an intern (dev), gets promoted to senior (staging) after passing tests, and finally becomes manager (production) after final review. At each level, it must prove itself before moving up.","deepDive":[{"heading":"Environment Pipeline","text":"Dev: auto-deploy on each commit. Quick feedback. May be unstable. Staging: deploy from main after tests pass. Manual QA, integration tests. Performance tests on staging. Production: deploy after approval. Release branches for hotfixes."},{"heading":"Promotion Gates","text":"Automated: build success, unit tests, integration tests, E2E tests, linting, security scan, performance benchmark. Manual: QA approval, product owner sign-off, compliance review, security review. Environment-specific: smoke tests (can the app start?), health endpoints."},{"heading":"Promotion Strategies","text":"Git-tagged promotion: tag commit as \"staging-approved\" then \"prod-approved\". Artifact promotion: promote Docker image tag from dev to staging to prod. Pipeline parameter: specify target environment. Progressive: dev → staging → canary → prod."},{"heading":"Immutable Environments","text":"Never modify a running environment — build a new one. New artifact → new environment → switch traffic. Immutable = consistent, reproducible, auditable. Prevents configuration drift."}],"interviewAnswer":"","interviewQuestions":[{"question":"What is deployment promotion?","answer":"Moving an artifact through environments (dev → staging → prod) with validation at each step."},{"question":"What is a promotion gate?","answer":"A condition that must be met before promoting to the next environment (tests pass, approval given, security scan clear)."},{"question":"What is an immutable environment?","answer":"An environment that is never modified — always replaced with a fresh deployment for consistency."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Deployment Environments & Promotion</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Dev</text><text x=\"60\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Auto-deploy</text><line x1=\"110\" y1=\"48\" x2=\"120\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"130\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"180\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Staging</text><text x=\"180\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Tests + QA</text><line x1=\"230\" y1=\"48\" x2=\"240\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"250\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"300\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Canary</text><text x=\"300\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">% traffic test</text><line x1=\"350\" y1=\"48\" x2=\"360\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"370\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"420\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Production</text><text x=\"420\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Full traffic</text><text x=\"240\" y=\"100\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Deployment Promotion: Dev → Staging → Canary → Production. Gates at each stage. Immutable environments.</text></svg>","codeExamples":[{"title":"Promotion Pipeline","useCase":"Stage-gated deployment.","code":"# Dev: auto (every push)\n# Staging: on main after tests\n# Prod: manual approval trigger","description":""}],"mcqQuestions":[{"question":"Why use immutable environments?","options":["Saves money","Prevents configuration drift, ensures reproducibility","Faster deployments","Easier debugging"],"answer":1,"explanation":"Immutable environments prevent configuration drift — every deployment is a fresh build, ensuring consistency."}]};
TOPICS_DATA["cicd"]["cicd-iac"] = {"id":"cicd-iac","title":"Infrastructure as Code in CI/CD","difficulty":"advanced","estimatedMinutes":25,"tldr":["Infrastructure as Code (IaC) manages infrastructure (servers, networks, databases) through machine-readable definition files, not manual processes.","IaC in CI/CD: validate, plan, and apply infrastructure changes automatically as part of the pipeline.","Tools: Terraform, Pulumi, AWS CDK, CloudFormation, Ansible, Kubernetes manifests."],"laymanDefinition":"IaC is like having a blueprint for your house instead of telling the builder step by step. You define the whole infrastructure in files: \"I want a server, a database, this firewall rule.\" The CI/CD pipeline reads the blueprint and builds it automatically. Changes to the blueprint trigger infrastructure updates.","deepDive":[{"heading":"IaC Pipeline Stages","text":"Validate: syntax check, format check (terraform fmt). Plan: show what will change (terraform plan). Security scan: check for misconfigurations (tfsec, checkov, terrascan). Apply: make changes (terraform apply). Destroy: teardown preview environments."},{"heading":"State Management","text":"Terraform state: records real-world infrastructure. Store state remotely (S3, Terraform Cloud, Consul). State locking: prevent concurrent changes. Sensitive data: state may contain secrets (encrypt it). State versioning: track changes over time."},{"heading":"Preview Environments","text":"Temporary environments per PR/branch. Terraform workspace per feature branch. Destroy on PR merge/close. Great for review apps. Database: seed with test data. Cost: spin down when not in use."},{"heading":"GitOps","text":"Git as single source of truth for infrastructure. Pull-based deployment (Argo CD, Flux). Sync: desired state in Git = actual state in cluster. Drift detection: auto-remediate configuration drift."}],"interviewAnswer":"","interviewQuestions":[{"question":"What is Infrastructure as Code?","answer":"Managing infrastructure through version-controlled definition files instead of manual processes."},{"question":"What are the three stages of IaC pipeline?","answer":"Validate (syntax), Plan (preview changes), Apply (make changes)."},{"question":"What is GitOps?","answer":"Using Git as the single source of truth for infrastructure, with automated sync to the actual environment."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Infrastructure as Code in CI/CD</text><rect x=\"10\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"60\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">IaC Files</text><text x=\"60\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Terraform, K8s YAML</text><line x1=\"110\" y1=\"48\" x2=\"120\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"130\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"180\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Plan</text><text x=\"180\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Validate + preview</text><line x1=\"230\" y1=\"48\" x2=\"240\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"250\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"300\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Apply</text><text x=\"300\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Provision infra</text><text x=\"240\" y=\"100\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">IaC in CI/CD: Validate, plan, then apply infrastructure changes automatically. GitOps for pull-based sync.</text></svg>","codeExamples":[{"title":"Terraform Pipeline","useCase":"Plan and apply in CI.","code":"terraform fmt -check\nterraform init\nterraform plan -out=tfplan\nterraform apply tfplan","description":""}],"mcqQuestions":[{"question":"What is the purpose of terraform plan?","options":["Apply changes immediately","Show what changes will be made without applying","Delete infrastructure","Format config files"],"answer":1,"explanation":"terraform plan previews the changes Terraform will make without actually applying them."}]};
TOPICS_DATA["cicd"]["cicd-monitoring"] = {"id":"cicd-monitoring","title":"Monitoring & Observability","difficulty":"advanced","estimatedMinutes":20,"tldr":["Monitoring and observability track application health, performance, and behavior in production and throughout the CI/CD pipeline.","Three pillars: logs (events), metrics (numbers), traces (request flows).","CI/CD integration: deploy-time checks, post-deploy monitoring, alerting on anomalies."],"laymanDefinition":"Monitoring is like having dashboard gauges and warning lights for your application. Logs tell you what happened (like a black box), metrics give you numbers (speed, error rate), and traces follow a single request through the system (like tracking a package).","deepDive":[{"heading":"Observability Pillars","text":"Logs: structured events (JSON). Centralized in ELK, Loki, CloudWatch. Metrics: numeric time-series data (Prometheus, Datadog). Traces: distributed tracing (Jaeger, Zipkin, OpenTelemetry). Dashboards: visualize data (Grafana)."},{"heading":"CI/CD Monitoring Integration","text":"Deploy health checks: verify app starts and responds after deploy. Smoke tests: run in production after deploy. Metric comparison: compare error rates before/after deploy. Release markers: annotate dashboards with deploy events. Canary analysis: compare metrics between versions."},{"heading":"Alerting","text":"Critical: page on-call (PagerDuty, OpsGenie). Warning: Slack notification. Info: dashboard annotation. Threshold-based: error rate > 1%, latency > 500ms. Anomaly-based: ML-based detection of unusual patterns. SLO-based: alert when approaching SLO burn rate."},{"heading":"Observability Tools","text":"Metrics: Prometheus, Datadog, New Relic. Logs: ELK (Elasticsearch, Logstash, Kibana), Loki, Splunk. Tracing: Jaeger, Zipkin, OpenTelemetry. Dashboards: Grafana, Datadog. Uptime: Pingdom, StatusCake. APM: New Relic, Datadog APM, Dynatrace."}],"interviewAnswer":"","interviewQuestions":[{"question":"What are the three pillars of observability?","answer":"Logs (events), Metrics (numbers), Traces (request flows)."},{"question":"What is a smoke test in deployment?","answer":"A quick test after deployment to verify the application starts and responds correctly in production."},{"question":"What is an SLO?","answer":"Service Level Objective — a target for reliability (e.g., 99.9% uptime, <500ms p99 latency)."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Monitoring & Observability</text><rect x=\"10\" y=\"35\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"80\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Logs</text><text x=\"80\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Events (ELK, Loki)</text><rect x=\"10\" y=\"65\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"80\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Metrics</text><text x=\"80\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Numbers (Prometheus)</text><rect x=\"10\" y=\"95\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"80\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Traces</text><text x=\"80\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Request flows (Jaeger)</text><rect x=\"10\" y=\"125\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"80\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Dashboards</text><text x=\"80\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Visualize (Grafana)</text><text x=\"240\" y=\"170\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Monitoring & Observability: Logs, Metrics, Traces. Post-deploy smoke tests, metric comparison, and alerting.</text></svg>","codeExamples":[{"title":"Health Check","useCase":"Simple deploy verification.","code":"curl -f http://myapp.com/health && echo \"Deploy OK\"","description":""}],"mcqQuestions":[{"question":"What is the first check after deployment?","options":["Load test","Health check verification","Database migration","Cache warmup"],"answer":1,"explanation":"A health check verifies the application starts and responds correctly immediately after deployment."}]};
TOPICS_DATA["cicd"]["cicd-security"] = {"id":"cicd-security","title":"CI/CD Security","difficulty":"advanced","estimatedMinutes":20,"tldr":["CI/CD security involves protecting the pipeline from attacks, securing secrets, and ensuring code integrity throughout the software supply chain.","Key areas: pipeline access control, dependency security, artifact integrity, secret management, compliance.","Supply chain attacks target CI/CD pipelines to inject malicious code."],"laymanDefinition":"CI/CD security is like securing the factory where your software is made. If someone breaks into the factory, they could tamper with the product. Security measures: locked doors (access control), ID checks (authentication), surveillance (audit logs), and tamper-evident packaging (artifact signing).","deepDive":[{"heading":"Pipeline Security","text":"Least privilege: pipelines should only access necessary resources. OIDC: use OpenID Connect instead of long-lived credentials. Environment protection: require approval for prod deployments. Audit logs: track all pipeline actions. Branch protection: prevent unauthorized changes."},{"heading":"Dependency Security","text":"Software Bill of Materials (SBOM): list all dependencies and versions. Dependency scanning: detect known vulnerabilities (npm audit, Snyk, Dependabot). Renovate/Dependabot: automated dependency updates. Lock files: pin exact dependency versions."},{"heading":"Artifact Integrity","text":"Sign artifacts: GPG signing, cosign (Sigstore). Verify signatures in pipeline. Checksums: verify artifact integrity. Provenance: attestation of build process (SLSA framework). Immutable tags: never overwrite published artifacts."},{"heading":"Supply Chain Security","text":"SLSA framework: security levels for supply chain (L1-L4). SBOM: CycloneDX, SPDX formats. Sigstore: free software signing service. cosign: container signing. in-toto: framework for supply chain integrity. GitHub Artifact Attestations: built-in provenance."}],"interviewAnswer":"","interviewQuestions":[{"question":"What is a software supply chain attack?","answer":"An attack that compromises the pipeline or dependencies to inject malicious code into software."},{"question":"What is SLSA?","answer":"Supply-chain Levels for Software Artifacts — a security framework with levels L1-L4 for supply chain integrity."},{"question":"What is Sigstore?","answer":"A free, open-source service for signing and verifying software artifacts (cosign)."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">CI/CD Security</text><rect x=\"10\" y=\"35\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"80\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Access Control</text><text x=\"80\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Least privilege</text><rect x=\"10\" y=\"65\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"80\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Dependency Scan</text><text x=\"80\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Snyk, Dependabot</text><rect x=\"10\" y=\"95\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"80\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Signing</text><text x=\"80\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Cosign, GPG</text><rect x=\"10\" y=\"125\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"80\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">SBOM</text><text x=\"80\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Dependency bill</text><text x=\"240\" y=\"170\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">CI/CD Security: Access control, dependency scanning, artifact signing, supply chain integrity (SLSA).</text></svg>","codeExamples":[{"title":"Cosign Sign","useCase":"Sign container image.","code":"cosign sign --key cosign.key ghcr.io/user/app:${SHA}\ncosign verify --key cosign.pub ghcr.io/user/app:${SHA}","description":""}],"mcqQuestions":[{"question":"What is SLSA Level 2?","options":["No security","Tamper resistance + provenance","Full isolation","Manual review"],"answer":1,"explanation":"SLSA Level 2 provides tamper resistance and provenance attestation for build artifacts."}]};
TOPICS_DATA["cicd"]["cicd-notifications"] = {"id":"cicd-notifications","title":"Pipeline Notifications","difficulty":"beginner","estimatedMinutes":10,"tldr":["Pipeline notifications alert teams about pipeline results: success, failure, or status changes.","Channels: Slack, email, Discord, Microsoft Teams, SMS/PagerDuty (critical failures).","Notifications should be actionable — not noise. Failed builds page on-call; success messages go to team channel."],"laymanDefinition":"Pipeline notifications are like automated status updates sent to your team. \"Tests passed!\" goes to the team chat. \"Deploy failed!\" pages the on-call engineer. The key is notifying the right people through the right channels with the right urgency.","deepDive":[{"heading":"Notification Types","text":"Success: post to team channel, deploy summary. Failure: @mention author, page on-call if production. Pending: optional, running status. Cancelled: log for audit. Warning: test flakiness, threshold warnings. Custom: deployment approval requests."},{"heading":"Tools and Integration","text":"Slack: incoming webhooks, Slack API (chat.postMessage). GitHub commit status: green/red/yellow checks. Email: SMTP or email API (SendGrid). PagerDuty, OpsGenie: critical alerts with escalation. Webhook: custom endpoints."},{"heading":"Best Practices","text":"Notify on: prod deployment failure, build failure on main. Don\\'t notify on: every dev branch commit success. Use @mentions to direct attention. Include: commit message, author, link to pipeline, error summary. Rate limit: avoid notification storms."}],"interviewAnswer":"","interviewQuestions":[{"question":"What is the most critical notification?","answer":"Production deployment failure — should page on-call engineer."},{"question":"What should notifications include?","answer":"Human-readable summary: what failed, who, which commit, link to logs."},{"question":"How to avoid notification fatigue?","answer":"Notify only on actionable events. Don\\'t spam on every branch success. Use appropriate channels for severity."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Pipeline Notifications</text><rect x=\"10\" y=\"35\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"80\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Pipeline Run</text><text x=\"80\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Build completes</text><line x1=\"150\" y1=\"48\" x2=\"170\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"180\" y=\"35\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"250\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Success?</text><text x=\"250\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Slack team channel</text><rect x=\"180\" y=\"65\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"250\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Failure?</text><text x=\"250\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Page on-call</text><text x=\"240\" y=\"130\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Pipeline Notifications: Success → team chat. Failure → page on-call. Actionable, not noisy.</text></svg>","codeExamples":[{"title":"Slack Notification","useCase":"Post build status to Slack.","code":"- name: Notify Slack\n  uses: slackapi/slack-github-action@v1\n  with:\n    payload: '{\"text\":\"Build ${{ job.status }}\"}'\n  env:\n    SLACK_WEBHOOK_URL: ${{ secrets.SLACK_WEBHOOK }}","description":""}],"mcqQuestions":[{"question":"What notification should page the on-call engineer?","options":["Testing complete","Build success","Production deployment failure","Dependency update available"],"answer":2,"explanation":"Production deployment failures are critical incidents that should page the on-call engineer immediately."}]};
TOPICS_DATA["cicd"]["cicd-jenkins"] = {"id":"cicd-jenkins","title":"Jenkins","difficulty":"intermediate","estimatedMinutes":25,"tldr":["Jenkins is an open-source automation server for CI/CD with a vast plugin ecosystem (1800+ plugins).","Pipeline defined as code (Jenkinsfile) using Declarative or Scripted pipeline syntax.","Key concepts: Master/Agent architecture, Jobs, Stages, Steps, Plugins, Shared Libraries."],"laymanDefinition":"Jenkins is the veteran of CI/CD tools — it's been around the longest and has a plugin for almost everything. It's like a customizable Swiss Army knife: more complex to set up than modern cloud alternatives, but extremely flexible and battle-tested.","deepDive":[{"heading":"Architecture","text":"Master (Controller): manages jobs, schedules builds, serves UI. Agents (Nodes): execute build jobs. Can run on different machines/containers. Agents can be: permanent (always on) or ephemeral (per-build containers). Distributed builds across multiple agents."},{"heading":"Jenkinsfile Pipeline","text":"Declarative: structured syntax (pipeline { agent any; stages { stage { steps } } }). Scripted: full Groovy flexibility. Both checked into repo (Pipeline as Code). Stages: organize build phases. Steps: individual commands. Post: actions after pipeline (always, success, failure)."},{"heading":"Plugins","text":"Source control: Git, GitHub, Bitbucket. Build: Maven, Gradle, npm, Docker. Test: JUnit, xUnit, TestNG. Notifications: Slack, Email, PagerDuty. Artifacts: Nexus, Artifactory. Infrastructure: Docker, Kubernetes, Terraform. Credentials: encrypted storage."},{"heading":"Shared Libraries","text":"Reusable pipeline code across repos. Loaded from Git repo. Global vars, steps, utilities. Version controlled. Reduces duplication. Example: pipelineLibrary { myLib } from github.com/org/jenkins-lib.git."}],"interviewAnswer":"","interviewQuestions":[{"question":"What is Jenkins?","answer":"An open-source CI/CD automation server with extensive plugin ecosystem."},{"question":"What is a Jenkinsfile?","answer":"A Groovy-based pipeline definition file stored in the repository (Pipeline as Code)."},{"question":"What is the Jenkins master-agent architecture?","answer":"Master manages jobs; agents execute builds. Agents can be permanent or ephemeral (containers)."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">Jenkins</text><rect x=\"10\" y=\"35\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"80\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Jenkins Master</text><text x=\"80\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Job management</text><line x1=\"150\" y1=\"48\" x2=\"170\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"180\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"230\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Agent 1</text><text x=\"230\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Ubuntu build</text><rect x=\"180\" y=\"65\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"230\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Agent 2</text><text x=\"230\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Windows build</text><text x=\"240\" y=\"120\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">Jenkins: Open-source CI/CD automation. Master/Agent architecture, 1800+ plugins, Pipeline as Code with Groovy.</text></svg>","codeExamples":[{"title":"Declarative Jenkinsfile","useCase":"Basic pipeline example.","code":"pipeline {\n    agent any\n    stages {\n        stage('Build') { steps { sh 'npm ci && npm run build' } }\n        stage('Test') { steps { sh 'npm test' } }\n        stage('Deploy') { steps { sh 'docker push app:latest' } }\n    }\n    post { failure { mail to: 'team@co', subject: \"Build failed\" } }\n}","description":""}],"mcqQuestions":[{"question":"What is a Jenkins Shared Library?","options":["A plugin store","Reusable pipeline code across repos","A Docker registry","A monitoring tool"],"answer":1,"explanation":"Shared Libraries allow reusable pipeline code (steps, functions) to be shared across multiple repositories."}]};
TOPICS_DATA["cicd"]["cicd-gitlab"] = {"id":"cicd-gitlab","title":"GitLab CI/CD","difficulty":"intermediate","estimatedMinutes":20,"tldr":["GitLab CI/CD is a built-in CI/CD system in GitLab, configured via .gitlab-ci.yml in the repository root.","Runners execute jobs: GitLab-hosted (SaaS) or self-managed. Jobs run in isolated environments (containers, VMs).","Key concepts: stages, jobs, artifacts, environments, variables, cache, multi-project pipelines."],"laymanDefinition":"GitLab CI/CD is like having your DevOps platform all in one place. Git, CI/CD, registry, and monitoring are integrated — no need to piece together different tools. The pipeline is defined in a .gitlab-ci.yml file in your repo, making it version-controlled like code.","deepDive":[{"heading":"GitLab CI YAML","text":"Stages: define order (build, test, deploy). Jobs: belong to stages, run in parallel within same stage. Script: shell commands to execute. Only/except: rules for when to run. Variables: CI/CD variables (key-value). Cache: shared between jobs. Artifacts: job outputs for later stages."},{"heading":"Runners","text":"GitLab-hosted: managed by GitLab (limited minutes on free tier). Self-managed: install gitlab-runner on your own infrastructure. Specific: assigned to specific projects. Shared: available to all projects in group. Group: assigned to groups. Tags: select runner by tag."},{"heading":"Advanced Features","text":"Multi-project pipelines: trigger downstream projects. Parent-child pipelines: dynamic pipeline generation. Review apps: per-branch preview environments. Auto DevOps: automatic CI/CD for common stacks. Dependencies: pass artifacts between jobs. Needs: DAG for parallel execution."},{"heading":"GitLab vs Jenkins","text":"GitLab: integrated (single vendor), simpler, SaaS option, containers-native. Jenkins: more flexible, more plugins, mature, complex. Choose GitLab for simplicity + integration, Jenkins for complex enterprise needs."}],"interviewAnswer":"","interviewQuestions":[{"question":"What file configures GitLab CI/CD?","answer":".gitlab-ci.yml in the repository root."},{"question":"What is a GitLab Runner?","answer":"An agent that executes CI/CD jobs. Can be GitLab-hosted (SaaS) or self-managed."},{"question":"What are GitLab Review Apps?","answer":"Per-branch preview environments that spin up automatically for each MR."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">GitLab CI/CD</text><rect x=\"10\" y=\"35\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"80\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">.gitlab-ci.yml</text><text x=\"80\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Pipeline config</text><line x1=\"150\" y1=\"48\" x2=\"170\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"180\" y=\"35\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"250\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">GitLab Runners</text><text x=\"250\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Execute jobs</text><rect x=\"180\" y=\"65\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"250\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Artifacts</text><text x=\"250\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Share between stages</text><text x=\"240\" y=\"110\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">GitLab CI/CD: Built-in CI/CD with .gitlab-ci.yml. Runners, artifacts, environments, multi-project pipelines.</text></svg>","codeExamples":[{"title":".gitlab-ci.yml","useCase":"Basic pipeline example.","code":"stages: [build, test, deploy]\nbuild:\n  stage: build\n  script: npm ci && npm run build\n  artifacts: paths: [dist/]","description":""}],"mcqQuestions":[{"question":"Where does GitLab CI/CD configuration live?","options":["Jenkinsfile",".gitlab-ci.yml","Dockerfile","config.yml"],"answer":1,"explanation":"GitLab CI/CD is configured via .gitlab-ci.yml stored in the repository root."}]};
TOPICS_DATA["cicd"]["cicd-circleci"] = {"id":"cicd-circleci","title":"CircleCI","difficulty":"intermediate","estimatedMinutes":15,"tldr":["CircleCI is a cloud-native CI/CD platform emphasizing speed, parallelism, and Docker-native execution.","Configuration via .circleci/config.yml. Jobs run in containers (Docker) or VMs.","Key features: orbs (reusable configs), parallelism, caching, workflows, SSH debug."],"laymanDefinition":"CircleCI is like a modern, cloud-first CI/CD service optimized for speed. It spins up fresh Docker containers for every build (no \"works on my machine\"), runs tests in parallel automatically, and uses orbs for reusable configuration. It's known for fast setup and execution.","deepDive":[{"heading":"Configuration","text":".circleci/config.yml: pipeline definition. Jobs: units of work. Steps: run commands. Workflows: orchestrate job order. Docker: specify image for job environment. Resource class: CPU/memory size (small, medium, large). Parallelism: auto-split tests across containers."},{"heading":"Orbs","text":"Reusable configuration packages (circleci.com/orbs). Official orbs: node, python, aws-cli, slack, browser-tools. Third-party orbs. Parameters for customization. Package your own orb for team use."},{"heading":"Key Features","text":"SSH debug: SSH into failing job for debugging (rerun with SSH). Cache: dependency caching (save_cache, restore_cache). Workspaces: pass files between jobs in workflow. Pipelines: trigger on push, PR, schedule, API. Contexts: shared environment variables across projects."},{"heading":"CircleCI vs GitHub Actions","text":"CircleCI: dedicated CI company, parallelism-focused, orbs ecosystem, SSD-native executors. GitHub Actions: integrated with GitHub, larger ecosystem (Marketplace), wider trigger events, no separate billing. Choose based on where your code lives and integration needs."}],"interviewAnswer":"","interviewQuestions":[{"question":"What is CircleCI?","answer":"A cloud-native CI/CD platform with Docker-native execution, parallelism, and orbs."},{"question":"What are CircleCI Orbs?","answer":"Reusable configuration packages that encapsulate jobs, commands, and executors."},{"question":"How does CircleCI handle parallelism?","answer":"Automatically splits test files across multiple containers using the parallelism setting."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">CircleCI</text><rect x=\"10\" y=\"35\" width=\"140\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"80\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">.circleci/config.yml</text><text x=\"80\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Pipeline config</text><line x1=\"150\" y1=\"48\" x2=\"170\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"180\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"230\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Docker Container</text><text x=\"230\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Build environment</text><line x1=\"280\" y1=\"48\" x2=\"290\" y2=\"48\" stroke=\"#666\" stroke-width=\"1.5\" marker-end=\"url(#arrow)\"/><rect x=\"300\" y=\"35\" width=\"100\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"350\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Workflows</text><text x=\"350\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Job orchestration</text><text x=\"240\" y=\"110\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">CircleCI: Cloud-native CI/CD. Docker execution, parallelism, orbs, workflows. Fast and developer-friendly.</text></svg>","codeExamples":[{"title":"CircleCI Config","useCase":"Basic config.yml.","code":"version: 2.1\norbs:\n  node: circleci/node@5\njobs:\n  build:\n    docker:\n      - image: cimg/node:20.3\n    steps:\n      - checkout\n      - node/install-packages\n      - run: npm test","description":""}],"mcqQuestions":[{"question":"What feature allows debugging CircleCI job failures?","options":["Cache","SSH debug rerun","Orbs","Workspaces"],"answer":1,"explanation":"CircleCI allows rerunning failed jobs with SSH access for interactive debugging."}]};
TOPICS_DATA["cicd"]["cicd-best-practices"] = {"id":"cicd-best-practices","title":"CI/CD Best Practices","difficulty":"intermediate","estimatedMinutes":20,"tldr":["CI/CD best practices ensure pipelines are fast, reliable, secure, and maintainable.","Key principles: fail fast, pipeline as code, idempotent stages, test in prod-like environments, immutable artifacts.","Continuously improve the pipeline — treat it like product code."],"laymanDefinition":"CI/CD best practices are like the rules of the road for your pipeline. They keep everything running smoothly: fail fast when something breaks, test in environments that mirror production, make builds reproducible, and treat your pipeline configuration with the same care as your application code.","deepDive":[{"heading":"Pipeline Design","text":"Fail fast: run quickest, most important checks first. Pipeline as code: version-controlled, reviewable, auditable. Idempotent: same commit always produces same result. Small, focused stages: one responsibility per stage. Parallelism: run independent tasks concurrently."},{"heading":"Security","text":"Never hardcode credentials — use secrets management. Least privilege: pipelines access only what they need. Scan dependencies for vulnerabilities. Sign artifacts. Audit pipeline changes. Branch protection on main."},{"heading":"Reliability","text":"Pin dependency versions (lock files). Use clean install commands (npm ci, pip install --require-hashes). Deterministic builds: same input = same output. Ephemeral agents: fresh environment per build. Cache strategically, but test without cache periodically."},{"heading":"Speed","text":"Optimize dependency caching. Run tests in parallel. Split large test suites. Use fast, focused test suites. Build only what changed (monorepo tools). Use appropriate runner sizes. Cancel redundant builds (e.g., only latest commit)."},{"heading":"Maintainability","text":"Use shared pipeline libraries (reusable steps). Document pipeline structure. Add pipeline tests (test the tests). Review pipeline changes like code. Monitor pipeline performance (duration, flakiness). Regular cleanup of old artifacts."}],"interviewAnswer":"","interviewQuestions":[{"question":"What does \"fail fast\" mean in CI/CD?","answer":"Run the quickest, most important checks first to provide immediate feedback on failures."},{"question":"Why should pipelines be idempotent?","answer":"Same commit should always produce the same result, regardless of when or how many times it runs."},{"question":"What is the benefit of ephemeral build agents?","answer":"Fresh environment per build eliminates configuration drift and ensures consistency."}],"diagramSvg":"<svg viewBox=\"0 0 500 200\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:sans-serif\"><rect x=\"0\" y=\"0\" width=\"500\" height=\"200\" rx=\"8\" fill=\"#f8f9fa\" stroke=\"#dee2e6\" stroke-width=\"1\"/><text x=\"250\" y=\"24\" text-anchor=\"middle\" font-size=\"14\" font-weight=\"bold\" fill=\"#333\">CI/CD Best Practices</text><rect x=\"10\" y=\"35\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#0070f3\" stroke=\"#0070f3\" stroke-width=\"1\"/><text x=\"65\" y=\"51\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Fail Fast</text><text x=\"65\" y=\"63\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Quickest checks first</text><rect x=\"10\" y=\"65\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#28a745\" stroke=\"#28a745\" stroke-width=\"1\"/><text x=\"65\" y=\"81\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Idempotent</text><text x=\"65\" y=\"93\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Same input = same output</text><rect x=\"10\" y=\"95\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#ffc107\" stroke=\"#ffc107\" stroke-width=\"1\"/><text x=\"65\" y=\"111\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Secure</text><text x=\"65\" y=\"123\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Secrets, least privilege</text><rect x=\"10\" y=\"125\" width=\"110\" height=\"25\" rx=\"4\" fill=\"#dc3545\" stroke=\"#dc3545\" stroke-width=\"1\"/><text x=\"65\" y=\"141\" text-anchor=\"middle\" font-size=\"11\" font-weight=\"bold\" fill=\"#fff\">Fast</text><text x=\"65\" y=\"153\" text-anchor=\"middle\" font-size=\"9\" fill=\"#ddd\">Parallel, caching</text><text x=\"240\" y=\"170\" font-size=\"9\" fill=\"#666\" text-anchor=\"middle\">CI/CD Best Practices: Fail fast, idempotent builds, security, speed, maintainability. Pipeline as code.</text></svg>","codeExamples":[{"title":"Pipeline Checklist","useCase":"Key CI/CD practices.","code":"# Fast feedback: lint first\n# Idempotent: lock files + clean install\n# Secure: secrets management\n# Maintainable: shared libraries","description":""}],"mcqQuestions":[{"question":"What makes a pipeline idempotent?","options":["Running once","Same commit always produces same result","Fast execution","Parallel stages"],"answer":1,"explanation":"Idempotence means the same commit always produces the same build output, regardless of when or how many times it runs."}]};